<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  * { box-sizing: border-box; }
  body {
    font-family: Arial, Helvetica, sans-serif;
    max-width: 760px;
    margin: 0 auto;
    padding: 20px;
    background: #f5f6f8;
    color: #222;
  }
  h1 { font-size: 1.5rem; margin: 0 0 16px; }
  form, .filters, #summary {
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 14px;
    margin-bottom: 14px;
  }
  .row { display: flex; flex-wrap: wrap; gap: 10px; align-items: flex-end; }
  .field { display: flex; flex-direction: column; gap: 4px; }
  .field.grow { flex: 1; min-width: 140px; }
  label { font-size: 0.8rem; color: #555; }
  input, select, button {
    font: inherit;
    padding: 7px 9px;
    border: 1px solid #bbb;
    border-radius: 5px;
    background: #fff;
  }
  input:focus, select:focus { outline: 2px solid #93c5fd; border-color: #2563eb; }
  button { cursor: pointer; }
  #add-expense { background: #2563eb; color: #fff; border-color: #2563eb; }
  #add-expense:hover { background: #1d4ed8; }
  #form-error {
    color: #c0392b;
    min-height: 1.2em;
    margin: -6px 2px 10px;
    font-size: 0.9rem;
  }
  .filters .row { align-items: flex-end; }
  #summary .grand { font-weight: bold; margin-bottom: 8px; }
  .cat-total {
    display: inline-block;
    margin: 2px 14px 2px 0;
    font-size: 0.9rem;
    color: #444;
    background: #f1f5f9;
    border-radius: 10px;
    padding: 3px 10px;
  }
  .expense {
    display: flex;
    gap: 10px;
    align-items: center;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 9px 12px;
    margin-bottom: 8px;
    flex-wrap: wrap;
  }
  .exp-amount { font-weight: bold; min-width: 80px; }
  .exp-category {
    background: #eef2ff;
    color: #3730a3;
    border-radius: 10px;
    padding: 2px 10px;
    font-size: 0.85rem;
  }
  .exp-date { color: #666; font-size: 0.9rem; }
  .exp-note { color: #777; font-size: 0.85rem; flex: 1; min-width: 100px; }
  .exp-del {
    margin-left: auto;
    background: #fee2e2;
    color: #b91c1c;
    border: 1px solid #fecaca;
    padding: 4px 10px;
    font-size: 0.85rem;
  }
  .exp-del:hover { background: #fecaca; }
  #empty { color: #888; text-align: center; padding: 14px; }
</style>
</head>
<body>

<h1>Personal Expense Tracker</h1>

<form id="expense-form" novalidate>
  <div class="row">
    <div class="field">
      <label for="amount">Amount</label>
      <input type="number" id="amount" step="0.01" placeholder="0.00">
    </div>
    <div class="field">
      <label for="category">Category</label>
      <select id="category">
        <option value="groceries">groceries</option>
        <option value="transport">transport</option>
        <option value="bills">bills</option>
        <option value="fun">fun</option>
      </select>
    </div>
    <div class="field">
      <label for="date">Date</label>
      <input type="date" id="date">
    </div>
    <div class="field grow">
      <label for="note">Note (optional)</label>
      <input type="text" id="note" placeholder="e.g. weekly shop">
    </div>
    <button type="submit" id="add-expense">Add Expense</button>
  </div>
</form>
<p id="form-error" role="alert"></p>

<div class="filters">
  <div class="row">
    <div class="field">
      <label for="filter-category">Filter category</label>
      <select id="filter-category">
        <option value="all">all</option>
        <option value="groceries">groceries</option>
        <option value="transport">transport</option>
        <option value="bills">bills</option>
        <option value="fun">fun</option>
      </select>
    </div>
    <div class="field">
      <label for="filter-from">From</label>
      <input type="date" id="filter-from">
    </div>
    <div class="field">
      <label for="filter-to">To</label>
      <input type="date" id="filter-to">
    </div>
  </div>
</div>

<div id="summary">
  <div class="grand">Total (visible): <span id="total">0.00</span></div>
  <div class="cat-total" data-cat="groceries">groceries: 0.00</div>
  <div class="cat-total" data-cat="transport">transport: 0.00</div>
  <div class="cat-total" data-cat="bills">bills: 0.00</div>
  <div class="cat-total" data-cat="fun">fun: 0.00</div>
</div>

<div id="expense-list"></div>
<div id="empty">No expenses to show.</div>

<script>
(function () {
  'use strict';

  var CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];
  var STORAGE_KEY = 'expense-tracker-expenses';

  var form        = document.getElementById('expense-form');
  var amountEl    = document.getElementById('amount');
  var categoryEl  = document.getElementById('category');
  var dateEl      = document.getElementById('date');
  var noteEl      = document.getElementById('note');
  var errorEl     = document.getElementById('form-error');
  var filterCatEl = document.getElementById('filter-category');
  var filterFromEl= document.getElementById('filter-from');
  var filterToEl  = document.getElementById('filter-to');
  var totalEl     = document.getElementById('total');
  var listEl      = document.getElementById('expense-list');
  var emptyEl     = document.getElementById('empty');

  var expenses = loadExpenses();
  var nextId = expenses.reduce(function (m, e) { return Math.max(m, e.id || 0); }, 0) + 1;

  function loadExpenses() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return [];
      var data = JSON.parse(raw);
      if (!Array.isArray(data)) return [];
      return data.filter(function (e) {
        return e && typeof e.amount === 'number' && isFinite(e.amount) &&
               typeof e.date === 'string' && e.date && e.category;
      });
    } catch (err) {
      return [];
    }
  }

  function saveExpenses() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
    } catch (err) { /* storage unavailable */ }
  }

  function showError(msg) { errorEl.textContent = msg; }
  function clearError()   { errorEl.textContent = ''; }

  form.addEventListener('submit', function (ev) {
    ev.preventDefault();

    var raw = amountEl.value.trim();
    var amount = raw === '' ? NaN : Number(raw);
    if (!isFinite(amount) || amount <= 0) {
      showError('Please enter a valid amount greater than zero.');
      amountEl.focus();
      return;
    }

    var date = dateEl.value;
    if (!date) {
      showError('Please choose a date for the expense.');
      dateEl.focus();
      return;
    }

    expenses.push({
      id: nextId++,
      amount: Math.round(amount * 100) / 100,
      category: categoryEl.value,
      date: date,
      note: noteEl.value.trim()
    });
    saveExpenses();

    clearError();
    amountEl.value = '';
    noteEl.value = '';
    amountEl.focus();
    render();
  });

  amountEl.addEventListener('input', clearError);
  dateEl.addEventListener('input', clearError);

  listEl.addEventListener('click', function (ev) {
    var btn = ev.target && ev.target.closest ? ev.target.closest('.exp-del') : null;
    if (!btn) return;
    var id = Number(btn.getAttribute('data-id'));
    expenses = expenses.filter(function (e) { return e.id !== id; });
    saveExpenses();
    render();
  });

  [filterCatEl, filterFromEl, filterToEl].forEach(function (el) {
    el.addEventListener('change', render);
    el.addEventListener('input', render);
  });

  function getVisible() {
    var cat  = filterCatEl.value;
    var from = filterFromEl.value;
    var to   = filterToEl.value;
    return expenses.filter(function (e) {
      if (cat !== 'all' && e.category !== cat) return false;
      if (from && e.date < from) return false;
      if (to && e.date > to) return false;
      return true;
    }).sort(function (a, b) {
      if (a.date !== b.date) return a.date < b.date ? 1 : -1;
      return b.id - a.id; // newest first
    });
  }

  function sum(list) {
    return list.reduce(function (s, e) { return s + e.amount; }, 0);
  }

  function buildRow(e) {
    var row = document.createElement('div');
    row.className = 'expense';

    var amt = document.createElement('span');
    amt.className = 'exp-amount';
    amt.textContent = '$' + e.amount.toFixed(2);
    row.appendChild(amt);

    var cat = document.createElement('span');
    cat.className = 'exp-category';
    cat.textContent = e.category;
    row.appendChild(cat);

    var dt = document.createElement('span');
    dt.className = 'exp-date';
    dt.textContent = e.date;
    row.appendChild(dt);

    if (e.note) {
      var nt = document.createElement('span');
      nt.className = 'exp-note';
      nt.textContent = e.note;
      row.appendChild(nt);
    }

    var del = document.createElement('button');
    del.type = 'button';
    del.className = 'exp-del';
    del.setAttribute('data-id', e.id);
    del.textContent = 'Delete';
    row.appendChild(del);

    return row;
  }

  function render() {
    var visible = getVisible();

    listEl.innerHTML = '';
    visible.forEach(function (e) { listEl.appendChild(buildRow(e)); });
    emptyEl.style.display = visible.length ? 'none' : 'block';

    totalEl.textContent = sum(visible).toFixed(2);

    CATEGORIES.forEach(function (c) {
      var el = document.querySelector('.cat-total[data-cat="' + c + '"]');
      if (el) {
        var catSum = sum(visible.filter(function (e) { return e.category === c; }));
        el.textContent = c + ': ' + catSum.toFixed(2);
      }
    });
  }

  // Default the entry date to today (local time).
  var now = new Date();
  dateEl.value =
    now.getFullYear() + '-' +
    String(now.getMonth() + 1).padStart(2, '0') + '-' +
    String(now.getDate()).padStart(2, '0');

  render();
})();
</script>

</body>
</html>
